<template>
	<div ref="cv" id="cv-content" class="pt-3 pt-md-5">
		<section class="container pb-5">
			<Header :data="{ first_name, last_name, social, email, tel, privacy }" />
		</section>

		<section class="container pb-5">
			<Summary :data="{ tag, introduce }" />
		</section>

		<section class="container pb-5">
			<h2 class="mb-3"><i class="bi bi-speedometer2 text-primary"></i> Skills</h2>
			<SkillGage v-for="s in skill" :key="s.name" :skill="s" class="mb-2" />
		</section>

		<div class="container">
			<div class="row">
				<section class="col-12 col-md-6 pb-5">
					<h2 class="mb-3"><i class="bi bi-pencil text-primary"></i> Education</h2>
					<Thread :list="education" />
				</section>

				<section class="col-12 col-md-6 pb-5">
					<h2 class="mb-3"><i class="bi bi-briefcase text-primary"></i> Experience</h2>
					<Thread :list="experience" />
				</section>
			</div>
		</div>

		<div class="container">
			<div class="row">
				<section class="col-12 col-md-6 pb-5">
					<h2 class="mb-3"><i class="bi bi-chat-quote text-primary"></i> Language</h2>
					<StarRank :list="language" />
				</section>

				<section class="col-12 col-md-6 pb-5">
					<h2 class="mb-4"><i class="bi bi-joystick text-primary"></i> Hobby</h2>
					<Hobby :list="hobby" />
				</section>
			</div>
		</div>
	</div>

	<a @click="downloadCV" id="cv-download-btn" class="d-flex align-items-center" data-html2canvas-ignore>
		<i class="bi bi-cloud-arrow-down"></i>
		<small class="ml-1">download cv</small>
	</a>
</template>

<script>
	import SkillGage from '@/components/SkillGage';
	import Thread from '@/components/Thread';
	import StarRank from '@/components/StarRank';
	import Hobby from '@/components/Hobby';
	import Header from '@/components/aboutme/Header.vue';
	import Summary from '@/components/aboutme/Summary.vue';
	import html2pdf from 'html2pdf.js';
	import { createNamespacedHelpers } from 'vuex';
	const { mapState } = createNamespacedHelpers('me');

	export default {
		computed: {
			...mapState([
				'first_name',
				'last_name',
				'tag',
				'introduce',
				'skill',
				'tel',
				'email',
				'privacy',
				'education',
				'experience',
				'language',
				'hobby',
				'social',
			]),
		},
		components: {
			SkillGage,
			Thread,
			StarRank,
			Hobby,
			Header,
			Summary,
		},
		methods: {
			downloadCV() {
				const el = document.querySelector('main');
				let { width, height } = el.getBoundingClientRect();
				width = Math.floor(width);
				height = Math.floor(height);

				const option = {
					filename: `${this.first_name}_${this.last_name}.pdf`,
					enableLinks: true,
					margin: 0,
					html2canvas: {
						dpi: 192,
						letterRendering: true,
						scale: 2,
						// x: 0,
						// y: 0,
						scrollX: 0,
						scrollY: 0,
						// windowWidth: 790,
						width: width,
						height: height,
						backgroundColor: 'black',
					},
					jsPDF: {
						unit: 'px',
						hotfix: ['px_scaling'],
						format: [width, height + 1],
						orientation: 'portrait',
					},
				};
				html2pdf().set(option).from(el).save();
			},
		},
	};
</script>

